import React from 'react';
import SarthakInvoiceForm from './SarthakInvoiceForm';
import InfinityInvoiceForm from './InfinityInvoiceForm';
import ShreepatiInvoiceForm from './ShreepatiInvoiceForm';

const AccountantInvoiceForm = (props) => {
  // We use the database-driven templateType to render the correct format
  // Fallback to name checking just in case the db field isn't set yet during transition
  
  const companyNameUpper = (props.companyName || "").toUpperCase();
  
  if (props.templateType === 'BILL_OF_SUPPLY' || companyNameUpper.includes("INFINITY GREEN") || companyNameUpper.includes("INFNITY GREEN")) {
    return <InfinityInvoiceForm {...props} />;
  }
  
  if (props.templateType === 'SIMPLIFIED_3_COL' || companyNameUpper.includes("SHREEPATI")) {
    return <ShreepatiInvoiceForm {...props} />;
  }

  // Default to TAX_INVOICE
  return <SarthakInvoiceForm {...props} />;
};

export default AccountantInvoiceForm;
